/**
 * MedX colors theme token runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Semantic color palette and supply-chain status hues.
 */
const COLORS_TOKENS = Object.freeze({
  primary: { value: "theme-colors-primary", scope: "theme" },
  secondary: { value: "theme-colors-secondary", scope: "theme" },
  muted: { value: "theme-colors-muted", scope: "theme" },
  accent: { value: "theme-colors-accent", scope: "theme" },
  surface: { value: "theme-colors-surface", scope: "theme" },
});

const COLORS_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const COLORS_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const colorsRegistry = new Map();
const COLORS_listeners = new Set();
let COLORS_seq = 0;

function createColorsId(prefix = "medx-theme-colors") {
  COLORS_seq += 1;
  return `${prefix}-${COLORS_seq}`;
}

function registerColors(config = {}) {
  const entryId = config.id ?? createColorsId();
  const preset = COLORS_PRESETS[config.preset ?? "default"] ?? COLORS_PRESETS.default;
  const token = COLORS_TOKENS[config.token ?? preset.token] ?? COLORS_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: COLORS_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  colorsRegistry.set(entryId, entry);
  notifyColorsListeners("register", entry);
  return entry;
}

function updateColors(id, patch = {}) {
  const entry = colorsRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyColorsListeners("update", entry);
  return entry;
}

function resolveColors(id) {
  const entry = colorsRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listColorsEntries(filter = {}) {
  let items = Array.from(colorsRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onColorsEvent(listener) {
  COLORS_listeners.add(listener);
  return () => COLORS_listeners.delete(listener);
}

function notifyColorsListeners(type, entry) {
  for (const listener of COLORS_listeners) {
    try {
      listener({ type, entry, registrySize: colorsRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:theme:colors] listener error", err.message);
    }
  }
}

function getColorsMetrics() {
  const items = listColorsEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(COLORS_TOKENS).length,
    presets: Object.keys(COLORS_PRESETS).length,
  };
}

async function runMedxColors() {
  console.log("[medx:ui:theme:colors] runtime initialized");
  console.log(`[medx:ui:theme:colors] tokens=${Object.keys(COLORS_TOKENS).length} presets=${Object.keys(COLORS_PRESETS).length}`);

  const events = [];
  onColorsEvent((e) => events.push(e.type));

  const domains = Object.keys(COLORS_SUPPLY_CHAIN);
  const presets = Object.keys(COLORS_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerColors({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "theme/colors" },
    });
  }

  const first = listColorsEntries()[0];
  if (first) updateColors(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getColorsMetrics();
  const resolved = first ? resolveColors(first.id) : null;

  console.log(`[medx:ui:theme:colors] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:theme:colors] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:theme:colors] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:theme:colors] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:theme:colors] bootstrap complete");
}

module.exports = runMedxColors;
